import React, { useMemo, useState } from "react";
import "./HomePage.less";

import SocialBits from "components/SocialBits";
import TypingTexts from "components/TypingTexts";
import ModalContact from "components/ModalContact";
import GameContent from "components/GameContent";

import { PlayCircleOutlined, PauseCircleOutlined } from "@ant-design/icons";
import { Howl } from "howler";
import { Button } from "antd";
import { musicSynthwave } from "utils/constants";
// import Assinatura from "icons/Assinatura";

interface Props {}
const HomePage: React.FC<Props> = () => {
  const [modal, setModal] = useState(false);
  const [playingSong, setPlayingSong] = useState(false);
  const [playingGame, setPlayingGame] = useState(false);

  const audio = useMemo(
    () =>
      new Howl({
        src: musicSynthwave,
        onplay: () => setPlayingSong(true),
        onpause: () => setPlayingSong(false),
        loop: true,
      }),
    []
  );

  return (
    <>
      <div className="main-content">
        {/* <Assinatura /> */}
        <div className="body-content">
          <div className="awesome-intro" onClick={() => setModal(true)}>
            <h1>{!modal ? "PLAY IT!" : "🤔"}</h1>
          </div>
          <TypingTexts />
          <div className="about-socials">
            <SocialBits />
          </div>
          <div className="button-control">
            <Button
              size="middle"
              onClick={() => {
                if (!playingSong) {
                  audio.play();
                } else {
                  audio.pause();
                }
              }}
              icon={
                playingSong ? <PauseCircleOutlined /> : <PlayCircleOutlined />
              }
            >
              {playingSong ? "pause vibes" : "play vibes"}
            </Button>
          </div>
        </div>

        <div className="main-graph">
          <div className={`graph ${playingSong ? "animation" : ""}`} />
        </div>
        <GameContent
          closeGame={() => setPlayingGame(false)}
          open={playingGame}
        />
      </div>

      <ModalContact onClose={setModal} modal={modal} />
    </>
  );
};

export default HomePage;
