import { Button } from "antd";
import React from "react";
import "./GameContent.less";
import { CloseCircleOutlined } from "@ant-design/icons";

interface Props {
  closeGame: () => void;
  open: boolean;
}

const GameContent: React.FC<Props> = ({ closeGame, open }) => {
  return (
    <div className={`game-content ${open ? "active" : "disabled"}`}>
      <Button type="link" onClick={closeGame} icon={<CloseCircleOutlined />} />
    </div>
  );
};

export default GameContent;
